// pages/partner/partner.js
const DB = require('../../utils/db');
Page({
  data: {
    headerDate: '', myCodeChars: [], inputCode: '',
    partnerInfo: null, myInfo: {}, habits: [],
    myRec: {}, ptRec: {}, myHabitPct: {}, ptHabitPct: {},
    myCompleted: 0, myTotal: 0, myRate: 0, myStreak: 0,
    partnerCompleted: 0, partnerTotal: 0, partnerRate: 0, partnerStreak: 0,
    coupleDays: 0, shareOn: true,
    reactions: ['❤️','👏','💪','🔥','🌟','😄','🎉','🥰','💕','👍','🎊','😘'],
    recentReacts: [],
  },
  onLoad() { this.buildHeader(); this.load(); },
  onShow()  { this.load(); },
  buildHeader() {
    const d = new Date();
    const months = ['一月','二月','三月','四月','五月','六月','七月','八月','九月','十月','十一月','十二月'];
    const days = ['星期日','星期一','星期二','星期三','星期四','星期五','星期六'];
    const code = DB.getMyCoupleCode();
    this.setData({ headerDate: `${months[d.getMonth()]} · ${days[d.getDay()]}`, myCodeChars: code.split('') });
  },
  load() {
    const partner = DB.getPartnerInfo();
    const myInfo = wx.getStorageSync('userInfo') || { name: '我', avatar: '🙂' };
    const habits = DB.getHabits();
    const myRec = DB.getTodayRecords();
    const ptRec = DB.getPartnerTodayRecords();
    const shareOn = wx.getStorageSync('shareHabits') !== false;
    const recentReacts = DB.getReactions().slice(-6).reverse();
    const myHabitPct = {}, ptHabitPct = {};
    let myDone = 0, ptDone = 0;
    habits.forEach(h => {
      myHabitPct[h.id] = myRec[h.id] ? Math.min(Math.round(myRec[h.id].value/h.target*100),100) : 0;
      ptHabitPct[h.id] = ptRec[h.id] ? Math.min(Math.round(ptRec[h.id].value/h.target*100),100) : 0;
      if (myRec[h.id] && myRec[h.id].completed) myDone++;
      if (ptRec[h.id] && ptRec[h.id].completed) ptDone++;
    });
    const t = habits.length;
    const myRate = t > 0 ? Math.round(myDone/t*100) : 0;
    const ptRate = t > 0 ? Math.round(ptDone/t*100) : 0;
    const myStreak = DB.getTotalStreak();
    const ptStreak = wx.getStorageSync('partnerStreak') || 0;
    const coupleDays = partner ? Math.max(1, Math.floor((Date.now()-new Date(partner.bindTime).getTime())/(864e5))+1) : 0;
    this.setData({ partnerInfo: partner, myInfo, habits, myRec, ptRec, myHabitPct, ptHabitPct, myCompleted: myDone, myTotal: t, myRate, myStreak, partnerCompleted: ptDone, partnerTotal: t, partnerRate: ptRate, partnerStreak: ptStreak, coupleDays, shareOn, recentReacts });
  },
  copyCode() { wx.setClipboardData({ data: DB.getMyCoupleCode(), success: () => wx.showToast({ title: '已复制', icon: 'success' }) }); },
  onCodeInput(e) { this.setData({ inputCode: e.detail.value.toUpperCase() }); },
  bindPartner() {
    if (this.data.inputCode.length !== 6) { wx.showToast({ title: '请输入 6 位配对码', icon: 'none' }); return; }
    wx.showLoading({ title: '绑定中' });
    setTimeout(() => {
      wx.hideLoading();
      const p = DB.bindPartner(this.data.inputCode);
      p.avatar = ''; p.name = '我的搭档';
      wx.setStorageSync('partnerInfo', p);
      wx.showModal({ title: '🎉 绑定成功', content: '开始一起打卡吧！', showCancel: false, success: () => this.load() });
    }, 800);
  },
  sendReaction(e) { DB.sendReaction(e.currentTarget.dataset.e); this.load(); wx.showToast({ title: `已发送 ${e.currentTarget.dataset.e}`, icon: 'none', duration: 1000 }); },
  toggleShare() { const v = !this.data.shareOn; wx.setStorageSync('shareHabits', v); this.setData({ shareOn: v }); wx.showToast({ title: v ? '已开启共享' : '已关闭共享', icon: 'none' }); },
  unbind() {
    wx.showModal({ title: '解除绑定', content: '确定要解绑吗？', confirmColor: '#FF3B30', success: r => { if (r.confirm) { wx.removeStorageSync('partnerInfo'); this.load(); }}});
  }
});

