        return true;
      }
      return false;
    } catch (error) {
      console.error('撤销打卡失败:', error);
      wx.showToast({
        title: '撤销失败，请重试',
        icon: 'none',
        duration: 2000
      });
      return false;
    }
  },
  getHabitTarget(id) { const h = this.getHabits().find(x=>x.id===id); return h?h.target:1; },
  getHabitStreak(id) {
