  updateChallengeProgress() {
    try {
      const list = this.getChallenges();
      const today = this.getToday();
      const r = this.getTodayRecords();
      list.forEach(c => {
        if (c.status === 'active') {
          if (r[c.habitId] && r[c.habitId].completed && c.lastCountDate !== today) {
            c.myProgress = (c.myProgress || 0) + 1;
            c.lastCountDate = today;
          }
          if (c.myProgress >= c.targetDays) c.status = 'myComplete';
        }
      });
      wx.setStorageSync('challenges', list);
      return list;
    } catch (error) {
      console.error('更新挑战进度失败:', error);
      return this.getChallenges(); // 返回当前列表，不做更改
    }
  },

  // 存储使用情况监控
  getStorageInfo() {
    try {
      return wx.getStorageInfoSync();
    } catch (error) {
      console.error('获取存储信息失败:', error);
      return { currentSize: 0, limitSize: 10 * 1024 * 1024 }; // 默认10MB限制
    }
  },

  checkStorageUsage(warningThreshold = 0.8) { // 默认阈值80%
    try {
      const info = this.getStorageInfo();
      const usagePercent = info.currentSize / info.limitSize;
      const isNearLimit = usagePercent > warningThreshold;

      if (isNearLimit) {
        console.warn(`存储空间接近限制: ${Math.round(usagePercent * 100)}% 已使用`);
        // 可以在这里显示用户提示
        wx.showModal({
          title: '存储空间警告',
          content: `您的存储空间已使用 ${Math.round(usagePercent * 100)}%，建议清理历史数据。`,
          showCancel: true,
          confirmText: '知道了',
          cancelText: '忽略'
        });
      }

      return {
        currentSize: info.currentSize,
        limitSize: info.limitSize,
        usagePercent,
        isNearLimit
      };
    } catch (error) {
      console.error('检查存储使用情况失败:', error);
      return null;
    }
  },

  // 清理旧数据以减少存储使用
  cleanupOldRecords(daysToKeep = 90) {
    try {
      const all = this.getAllRecords();
      const today = new Date();
      const cutoffDate = new Date();
      cutoffDate.setDate(today.getDate() - daysToKeep);

      let deletedCount = 0;
      Object.keys(all).forEach(dateStr => {
        const recordDate = new Date(dateStr);
        if (recordDate < cutoffDate) {
          delete all[dateStr];
          deletedCount++;
        }
      });

      if (deletedCount > 0) {
        wx.setStorageSync('checkRecords', all);
        this._clearStreakCache(); // 清除缓存
        console.log(`已清理 ${deletedCount} 天前的旧记录`);
        return deletedCount;
      }
      return 0;
    } catch (error) {
      console.error('清理旧记录失败:', error);
      return 0;
    }
  }
};

